on_write:
let res = #{ action: "Allow" };
if type_of(payload) != "map" {
    res.action = "Abort";
    res.error = "ACID Violation: Payload must be a strictly typed map (table row)";
} else {
    if !payload.contains("id") || !payload.contains("created_at") {
        res.action = "Abort";
        res.error = "Schema Violation: Missing required columns 'id' or 'created_at'";
    }
}
res
